import{_ as a,o as r,c as e,a2 as o}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"05-5 航運週期判斷框架","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/航運產業/05_航運週期與景氣判斷/05-5_航運週期判斷框架.md","filePath":"Deep32Q知識庫/產業洞察/航運產業/05_航運週期與景氣判斷/05-5_航運週期判斷框架.md"}'),i={name:"Deep32Q知識庫/產業洞察/航運產業/05_航運週期與景氣判斷/05-5_航運週期判斷框架.md"};function n(d,t,s,l,h,c){return r(),e("div",null,[...t[0]||(t[0]=[o(`<h1 id="_05-5-航運週期判斷框架" tabindex="-1">05-5 航運週期判斷框架 <a class="header-anchor" href="#_05-5-航運週期判斷框架" aria-label="Permalink to &quot;05-5 航運週期判斷框架&quot;">​</a></h1><p><strong>更新日期：2026-05-14</strong><strong>研究範圍：全球海運週期理論、船隊動態、庫存週期與景氣預測</strong></p><hr><h2 id="一、航運超級週期理論-2020-2025-是否為超級週期" tabindex="-1">一、航運超級週期理論：2020-2025 是否為超級週期？ <a class="header-anchor" href="#一、航運超級週期理論-2020-2025-是否為超級週期" aria-label="Permalink to &quot;一、航運超級週期理論：2020-2025 是否為超級週期？&quot;">​</a></h2><p><strong>結論：container shipping 確實經歷了「超級週期」，但正於 2026 年進入結構性重置（structural reset）。</strong></p><h3 id="超級週期的定義與特徵" tabindex="-1">超級週期的定義與特徵 <a class="header-anchor" href="#超級週期的定義與特徵" aria-label="Permalink to &quot;超級週期的定義與特徵&quot;">​</a></h3><p>航運「超級週期」通常指持續 3-5 年以上、由結構性供需失衡驅動的高運價與高利潤週期。2020-2025 年的 container shipping 完全符合此定義：</p><table tabindex="0"><thead><tr><th>特徵</th><th>超級週期表現（2020-2025）</th></tr></thead><tbody><tr><td>運價</td><td>SCFI 指數創歷史新高，跨太平洋線運價飆升 5-10 倍</td></tr><tr><td>利潤率</td><td>六大聯盟（Maersk、MSC、CMA CGM 等）淨利率突破 30%</td></tr><tr><td>新船訂單</td><td>2021-2025 年間創紀錄增長，全年訂單達 480 萬 TEU（較前年 +42%）</td></tr><tr><td>全球訂單簿</td><td>達創紀錄的 1,180 萬 TEU（2026 年初），佔活躍船隊 33%——自 2010 年以來最高</td></tr></tbody></table><h3 id="超級週期的結束" tabindex="-1">超級週期的結束 <a class="header-anchor" href="#超級週期的結束" aria-label="Permalink to &quot;超級週期的結束&quot;">​</a></h3><p>根據 MareForum、Splash247、Clarksons 等機構分析，<strong>2026 年被廣泛認為是超級週期的終結年</strong>。關鍵轉折點：</p><ol><li><strong>新船交付潮</strong>：2025 年全球 container fleet 容量增長 6%（達約 3,235 萬 TEU），2026 年預計再增 3.6-5%（約 170 萬 TEU 新船交付）</li><li><strong>供需失衡</strong>：需求增長僅 2.5-3.5%，遠低於供給增速</li><li><strong>紅海通航正常化</strong>：若蘇伊士航道完全恢復，將額外釋放 6-8% 全球 container shipping 容量</li><li><strong>運價下跌</strong>：SCFI 指數 2025 年較 2024 年平均低 37%，2026 年預計再跌 10-25%</li></ol><p><strong>結論：2020-2025 年確實是 container shipping 的超級週期，但 2026 年起進入「結構性重置」階段，而非傳統意義上的超級週期延續。</strong></p><hr><h2 id="二、新船訂單-vs-拆解量-運力增減動態" tabindex="-1">二、新船訂單 vs 拆解量：運力增減動態 <a class="header-anchor" href="#二、新船訂單-vs-拆解量-運力增減動態" aria-label="Permalink to &quot;二、新船訂單 vs 拆解量：運力增減動態&quot;">​</a></h2><h3 id="_2026-年船隊動態全景" tabindex="-1">2026 年船隊動態全景 <a class="header-anchor" href="#_2026-年船隊動態全景" aria-label="Permalink to &quot;2026 年船隊動態全景&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>數值</th><th>備註</th></tr></thead><tbody><tr><td>全球 container 活躍船隊</td><td>~6,700 艘 / 3,400 萬 TEU</td><td>2026 年 4 月數據</td></tr><tr><td>訂單簿（Orderbook）</td><td>~1,180 萬 TEU（33% 活躍船隊）</td><td>2026 Q1，創歷史新高</td></tr><tr><td>2025 年新船交付量</td><td>~480 萬 TEU（+42% YoY）</td><td>創單年紀錄</td></tr><tr><td>2026 年新船交付預估</td><td>~170 萬 TEU（TEU）</td><td>持續但增速放緩</td></tr><tr><td>2025 年拆解量（container）</td><td>僅 12 艘 / 8,172 TEU</td><td>二十年來最低</td></tr><tr><td>全球所有船型拆解量</td><td>790 萬 GT（+65% YoY）</td><td>散貨船、油輪、LNG 帶動</td></tr></tbody></table><h3 id="關鍵洞察" tabindex="-1">關鍵洞察 <a class="header-anchor" href="#關鍵洞察" aria-label="Permalink to &quot;關鍵洞察&quot;">​</a></h3><ul><li><strong>拆解量極低的原因</strong>：船東在超級週期高利潤下傾向保留老舊船舶，將其作為戰略緩衝以應對供應鏈中斷</li><li><strong>BIMCO 警告</strong>：截至 2025 年 10 月，container ship「拆解滯後」（recycling overhang）至少 500 艘、180 萬 TEU</li><li><strong>2026 年拆解將加速</strong>：新船交付增加 + 紅海/蘇伊士航線變化，預計拆解活動將顯著上升</li><li><strong>跨船型差異</strong>：container 拆解仍低，但 LNG、散貨船、油輪的拆解量已大幅上升</li></ul><hr><h2 id="三、全球海運貿易量-vs-gdp-成長乘數" tabindex="-1">三、全球海運貿易量 vs GDP 成長乘數 <a class="header-anchor" href="#三、全球海運貿易量-vs-gdp-成長乘數" aria-label="Permalink to &quot;三、全球海運貿易量 vs GDP 成長乘數&quot;">​</a></h2><h3 id="海運貿易彈性-trade-to-gdp-elasticity" tabindex="-1">海運貿易彈性（Trade-to-GDP Elasticity） <a class="header-anchor" href="#海運貿易彈性-trade-to-gdp-elasticity" aria-label="Permalink to &quot;海運貿易彈性（Trade-to-GDP Elasticity）&quot;">​</a></h3><p>全球海運貿易量對 GDP 的彈性係數通常在 <strong>1.2-1.8</strong> 之間，意味著 GDP 每增長 1%，海運貿易量增長 1.2-1.8%。</p><h3 id="_2025-2026-年預測" tabindex="-1">2025-2026 年預測 <a class="header-anchor" href="#_2025-2026-年預測" aria-label="Permalink to &quot;2025-2026 年預測&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>2025 年</th><th>2026 年預估</th></tr></thead><tbody><tr><td>全球 GDP 成長</td><td>~2.8-3.0%</td><td>~2.5-2.8%（放緩）</td></tr><tr><td>海運貿易量成長</td><td>~3.0-3.5%</td><td>~2.5-3.5%（供需失衡加劇）</td></tr><tr><td>彈性係數</td><td>~1.0-1.2（偏低）</td><td>~0.9-1.1（持續偏低）</td></tr></tbody></table><h3 id="彈性偏低的驅動因素" tabindex="-1">彈性偏低的驅動因素 <a class="header-anchor" href="#彈性偏低的驅動因素" aria-label="Permalink to &quot;彈性偏低的驅動因素&quot;">​</a></h3><ol><li><strong>近岸外包（nearshoring）</strong>：部分製造業從亞洲轉向北美/歐洲，縮短海運航線</li><li><strong>庫存正常化</strong>：疫情期間的過度備貨已逐步消化，貿易量回歸常態</li><li><strong>地緣政治重組</strong>：紅海繞航增加實際運力需求，但貿易量本身未同步增長</li></ol><hr><h2 id="四、庫存週期-補庫存→去庫存對運價影響" tabindex="-1">四、庫存週期：補庫存→去庫存對運價影響 <a class="header-anchor" href="#四、庫存週期-補庫存→去庫存對運價影響" aria-label="Permalink to &quot;四、庫存週期：補庫存→去庫存對運價影響&quot;">​</a></h2><h3 id="當前階段-從「去庫存」轉向「補庫存」" tabindex="-1">當前階段：從「去庫存」轉向「補庫存」 <a class="header-anchor" href="#當前階段-從「去庫存」轉向「補庫存」" aria-label="Permalink to &quot;當前階段：從「去庫存」轉向「補庫存」&quot;">​</a></h3><p>2023-2024 年，全球經歷了大規模「去庫存」（destocking）週期，企業消耗疫情期間累積的過剩庫存。2025-2026 年正處於<strong>補庫存（restocking）的轉折點</strong>。</p><h3 id="庫存週期對運價的影響路徑" tabindex="-1">庫存週期對運價的影響路徑 <a class="header-anchor" href="#庫存週期對運價的影響路徑" aria-label="Permalink to &quot;庫存週期對運價的影響路徑&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>補庫存階段 → 倉庫利用率上升（必需品、電商、製造業）→ 貨量需求增加 → 運價上揚</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span> tariff front-loading（關稅前置）→ 2025 年初庫存週期扭曲 → 後續補庫成本更高</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span> 2026 年「關稅吸收牆」（tariff absorption wall）→ 成本轉嫁消費者</span></span></code></pre></div><h3 id="關鍵數據點" tabindex="-1">關鍵數據點 <a class="header-anchor" href="#關鍵數據點" aria-label="Permalink to &quot;關鍵數據點&quot;">​</a></h3><ul><li><strong>倉庫利用率</strong>：必需品、電商和製造業領域的倉庫利用率持續上升，客戶預計在 2026 年達到功能容量</li><li><strong>關稅前置效應</strong>：2025 年初多國企業為預期新關稅而提前備貨，導致庫存週期扭曲</li><li><strong>補庫成本</strong>：restocking 以比 2025 年高 15% 的成本進行（source: Tradlinx）</li><li><strong>運價影響</strong>：補庫存週期通常支撐運價 3-6 個月，但 2026 年因供給過剩，運價上漲空間有限</li></ul><hr><h2 id="五、環保法規強制降速-eexi-cii-→-有效運力減少" tabindex="-1">五、環保法規強制降速（EEXI/CII）→ 有效運力減少 <a class="header-anchor" href="#五、環保法規強制降速-eexi-cii-→-有效運力減少" aria-label="Permalink to &quot;五、環保法規強制降速（EEXI/CII）→ 有效運力減少&quot;">​</a></h2><h3 id="eexi-與-cii-的核心機制" tabindex="-1">EEXI 與 CII 的核心機制 <a class="header-anchor" href="#eexi-與-cii-的核心機制" aria-label="Permalink to &quot;EEXI 與 CII 的核心機制&quot;">​</a></h3><ul><li><strong>EEXI（Energy Efficiency Existing Ship Index）</strong>：一次性技術指標，要求現有船舶達到基於設計的能效基準。最常見且經濟的合規方式是「引擎功率限制」（Engine Power Limitation / ShaPoLi），實質上限制了船舶的最大速度。</li><li><strong>CII（Carbon Intensity Indicator）</strong>：年度營運碳強度指標，將船舶從 A（最佳）到 E（最差）分級。連續三年 D 或單年 E 需提交糾正計劃。</li></ul><h3 id="_2026-年-cii-第二階段-phase-2" tabindex="-1">2026 年 CII 第二階段（Phase 2） <a class="header-anchor" href="#_2026-年-cii-第二階段-phase-2" aria-label="Permalink to &quot;2026 年 CII 第二階段（Phase 2）&quot;">​</a></h3><ul><li><strong>年度減碳係數（Z factor）</strong>：2026 年為相對於 2019 基準的 <strong>11%</strong>，是 2023 年 5% 目標的兩倍多</li><li><strong>合規方式</strong>：降速（slow steaming）是最經濟的方式——以設計速度 75% 營運可減少 40-50% 燃料消耗</li><li><strong>有效運力損失</strong>：降速增加航程時間 5-10%，實質上從市場中減少了可用運力</li></ul><h3 id="對有效運力的淨影響" tabindex="-1">對有效運力的淨影響 <a class="header-anchor" href="#對有效運力的淨影響" aria-label="Permalink to &quot;對有效運力的淨影響&quot;">​</a></h3><table tabindex="0"><thead><tr><th>因素</th><th>正面（減少供給）</th><th>負面（增加供給）</th><th>淨效果</th></tr></thead><tbody><tr><td>EEXI/CII 降速</td><td>-5~10% 運力（2026）</td><td>—</td><td><strong>淨減少</strong></td></tr><tr><td>新船交付</td><td>—</td><td>+3.6~5% 容量（2026）</td><td><strong>淨增加</strong></td></tr><tr><td>紅海正常化</td><td>—</td><td>+6~8% 容量（若蘇伊士恢復）</td><td><strong>淨增加</strong></td></tr><tr><td>拆解加速</td><td>-2~3%（預估 2026）</td><td>—</td><td><strong>淨減少</strong></td></tr></tbody></table><p><strong>結論：環保法規的降速效应在 2026 年仍不足以完全抵消新船交付和紅海正常化帶來的供給增加，但減少了下跌幅度。</strong></p><hr><h2 id="六、未來-12-24-個月景氣預測共識-2026-q3-2027-q4" tabindex="-1">六、未來 12-24 個月景氣預測共識（2026 Q3 - 2027 Q4） <a class="header-anchor" href="#六、未來-12-24-個月景氣預測共識-2026-q3-2027-q4" aria-label="Permalink to &quot;六、未來 12-24 個月景氣預測共識（2026 Q3 - 2027 Q4）&quot;">​</a></h2><h3 id="市場共識總結" tabindex="-1">市場共識總結 <a class="header-anchor" href="#市場共識總結" aria-label="Permalink to &quot;市場共識總結&quot;">​</a></h3><table tabindex="0"><thead><tr><th>評估維度</th><th>預測方向</th><th>關鍵依據</th></tr></thead><tbody><tr><td>Container shipping</td><td><strong>下行週期</strong>（downcycle）</td><td>供給過剩 19% 平均，運價跌 10-25%</td></tr><tr><td>Crude tanker</td><td><strong>支撐性</strong>（supportive）</td><td>地緣中斷、繞航持續</td></tr><tr><td>Capesize dry bulk</td><td><strong>支撐性</strong>（supportive）</td><td>地緣風險、貨源穩定</td></tr><tr><td>LNG shipping</td><td><strong>拆解加速</strong></td><td>老舊船隊更新換代</td></tr><tr><td>運價趨勢</td><td>持續下跌但波動加劇</td><td>空航、停航等容量管理措施</td></tr></tbody></table><h3 id="三大關鍵變數-未來-12-24-個月" tabindex="-1">三大關鍵變數（未來 12-24 個月） <a class="header-anchor" href="#三大關鍵變數-未來-12-24-個月" aria-label="Permalink to &quot;三大關鍵變數（未來 12-24 個月）&quot;">​</a></h3><ol><li><strong>紅海/蘇伊士通航恢復程度</strong>：若完全恢復，container 供給過剩加劇；若持續繞航，則支撐運價</li><li><strong>關稅政策</strong>：美國 2025-2026 年關稅政策的實際執行力度，影響貿易流量</li><li><strong>環保法規加嚴</strong>：2026 年 CII Phase 2、EU ETS 100% 覆蓋，可能加速老舊船舶退出市場</li></ol><h3 id="景氣預測結論" tabindex="-1">景氣預測結論 <a class="header-anchor" href="#景氣預測結論" aria-label="Permalink to &quot;景氣預測結論&quot;">​</a></h3><p><strong>2026-2027 年：Container shipping 進入下行週期，但地緣政治風險（紅海、荷莫茲）和環保法規提供了下行保護。油輪和散貨船市場相對支撐。整體而言，2026 年是「結構性重置」年，而非超級週期的延續。</strong></p><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>MareForum (2026-05): &quot;Container Shipping: Structural Reset as Supercycle Ends&quot;</li><li>Splash247 (2026-05): &quot;Carriers Face Structural Reset as Container Supercycle Ends&quot;</li><li>Clarksons (2026-04): &quot;Global Orderbook at 15-Year High as 2025 Activity Eases&quot;</li><li>WorldCargoNews (2026-04): &quot;Global Container Fleet Surpasses 6,700 Ships&quot;</li><li>BIMCO (2025-10): &quot;Recycling Overhang of 500+ Container Ships&quot;</li><li>Xeneta (2026): &quot;October Spot Rate Spike 2026 Ocean Freight Tenders&quot;</li><li>Searoutes (2025-10): &quot;EEXI/CII Shipping Sustainability Regulations 2026-2028&quot;</li><li>UNCTAD (2025): &quot;Review of Maritime Transport&quot;</li></ol>`,54)])])}const u=a(i,[["render",n]]);export{p as __pageData,u as default};
